#:property AllowUnsafeBlocks=true

using System;

// Test stackalloc with nint (native-sized integer)
Span<nint> nativeInts = stackalloc nint[5];

for (int i = 0; i < nativeInts.Length; i++)
    nativeInts[i] = i * 10;

Console.WriteLine($"Span<nint> via stackalloc (length={nativeInts.Length}):");
for (int i = 0; i < nativeInts.Length; i++)
    Console.WriteLine($"  [{i}] = {nativeInts[i]}");

// Also test nuint (unsigned native-sized integer)
Span<nuint> nativeUInts = stackalloc nuint[3];
nativeUInts[0] = 100;
nativeUInts[1] = 200;
nativeUInts[2] = 300;

Console.WriteLine($"\nSpan<nuint> via stackalloc (length={nativeUInts.Length}):");
for (int i = 0; i < nativeUInts.Length; i++)
    Console.WriteLine($"  [{i}] = {nativeUInts[i]}");

Console.WriteLine($"\nnint size: {sizeof(nint)} bytes (IntPtr.Size = {IntPtr.Size})");

